try {
  const items = $input.all();
  return processarMensagens(items);
} catch (error) {
  console.error('Erro:', error);
  throw error;
}

function processarMensagens(items) {
  return items.map(item => {
    try {
      if (!item?.json?.Mensagem) return item;
      const original = item.json.Mensagem;
      let mensagem = original;
      if (typeof mensagem === 'object') mensagem = JSON.stringify(mensagem);
      if (typeof mensagem !== 'string') mensagem = String(mensagem ?? '');
      let mensagemLimpa = limparMensagem(mensagem);
      if (!mensagemLimpa || mensagemLimpa.length === 0) mensagemLimpa = String(original ?? '').trim();
      const LIMITE_CHAR = 4000;
      if (mensagemLimpa.length > LIMITE_CHAR) mensagemLimpa = mensagemLimpa.slice(mensagemLimpa.length - LIMITE_CHAR);
      if (mensagemLimpa && mensagemLimpa.length > 0) item.json.Mensagem = mensagemLimpa;
      return { json: item.json };
    } catch (error) {
      return item;
    }
  });
}

function extrairMensagemPrincipal(str) {
  const frases = str.split(/(?<=[.!?])\s+/);
  return frases.map(f => f.trim()).filter(f => f.length > 0 && !f.includes('tool_calls') && !f.includes('invalid_tool_calls') && !f.match(/^[:\s\[\]{}]+$/)).join(' ');
}

function limparCaracteresEspeciais(str) {
  return str.replace(/\\\\[rnt]/g, ' ').replace(/\\"/g, '').replace(/[\x00-\x1F\x7F-\x9F]/g, '').replace(/\"+/g, '').replace(/[{}\[\]]/g, '').trim();
}

function limparMensagem(texto) {
  if (typeof texto !== 'string') return '';
  let resultado = texto;
  if (resultado.includes('{') && resultado.includes('}') && resultado.includes('"tool_calls"') && !/[a-zA-ZÀ-ÿ]{3,}/.test(resultado)) return '';
  resultado = removerMetadataTecnico(resultado);
  resultado = extrairMensagemPrincipal(resultado);
  resultado = limparCaracteresEspeciais(resultado);
  resultado = resultado.replace(/\s+/g, ' ').replace(/^[\"",\s]+|[\"",\s]+$/g, '').trim();
  return resultado;
}

function removerMetadataTecnico(str) {
  return str.replace(/\"response_metadata\"\s*:\s*{[^}]*}/g, '').replace(/\"additional_kwargs\"\s*:\s*{[^}]*}/g, '').replace(/\"tool_calls\"\s*:\s*\[[^\]]*]/g, '').replace(/\"invalid_tool_calls\"\s*:\s*\[[^\]]*]/g, '').replace(/\"type\"\s*:\s*\"(ai|human)\"/g, '').replace(/\"data\"\s*:\s*{[^}]*}/g, '').replace(/,\s*{[^}]*}/g, '').replace(/,\s*\[\s*]/g, '').replace(/\s*:\s*null/g, '').replace(/\s*:\s*\[\]/g, '').replace(/\s*:\s*{}/g, '').replace(/\s+/g, ' ').replace(/^\s+|\s+$/g, '');
}

