const input = $input.all();
const raw = input[0]?.json || {};
const body = raw.body || {};
const ticket = body.ticket || {};
const msg = body.msg || {};
const msgContent = msg.message || {};

// Filtros: só processar mensagens reais (não fromMe, não outros eventos)
if (body.method !== 'message') return [];
if (msg.key?.fromMe === true) return [];

// Tipo de conteúdo detectado pela chave do objeto message
const msgKeys = Object.keys(msgContent);
let tipoConteudo = 'text';
if (msgKeys.includes('audioMessage'))    tipoConteudo = 'audio';
else if (msgKeys.includes('imageMessage'))    tipoConteudo = 'image';
else if (msgKeys.includes('documentMessage')) tipoConteudo = 'document';

// Conteúdo de texto
const conteudoMensagem = msgContent.conversation
  || msgContent.extendedTextMessage?.text
  || '';

// URL de mídia (se houver)
const urlConteudo = msgContent.audioMessage?.url
  || msgContent.imageMessage?.url
  || msgContent.documentMessage?.url
  || '';

return [{
